const handleReturn = async () => {
  if (!cart.length) return alert('Позиции для возврата не выбраны')

  /* backend ждёт объект { items:[...], reason:"..." } */
  const payload = {
    reason,
    items: cart.map(i => ({
      sale_item: i.id,   // id проданного товара
      quantity : i.qty
    }))
  }

  try {
    await API.createReturn(payload)
    alert('Возврат оформлен')
    setCart([])
    navigate('/returns-report')
  } catch (e) {
    console.error('Ошибка возврата', e)
    alert('Ошибка при возврате')
  }
}
